// Get the earthquake data from USGS response
const features = $input.first().json.features;

// If no earthquakes found, stop the workflow
if (!features || features.length === 0) {
  return [];
}

// Get the most recent earthquake
const latest = features[0];

// Extract the details we need
const quakeId = latest.id;
const mag = latest.properties.mag;
const place = latest.properties.place;
const felt = latest.properties.felt || 'No reports';
const alert = latest.properties.alert || 'None';
const tsunami = latest.properties.tsunami === 1 ? '⚠️ YES' : 'No';
const url = latest.properties.url;

// Convert UTC time to Dhaka time (UTC+6)
const utcTime = new Date(latest.properties.time);
const dhakaTime = new Date(utcTime.getTime() + (6 * 60 * 60 * 1000));
const time = dhakaTime.toLocaleString('en-GB', {
  day: '2-digit',
  month: 'short',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  second: '2-digit'
}) + ' (Dhaka time)';

// Deduplicate — only alert if this is a new earthquake we haven't seen before
const staticData = $getWorkflowStaticData('global');

if (staticData.lastQuakeId === quakeId) {
  // Same earthquake as last check — do nothing
  return [];
}

// New earthquake found — save its ID so we don't alert again
staticData.lastQuakeId = quakeId;

// Set emoji based on magnitude
let magEmoji = '🟡'; // moderate
if (mag >= 6.0) magEmoji = '🔴'; // strong
else if (mag >= 5.0) magEmoji = '🟠'; // moderate-strong
else if (mag < 4.0) magEmoji = '🟢'; // minor

// Set priority label based on magnitude
let priority = 'Minor';
if (mag >= 6.0) priority = '🚨 STRONG — Take cover!';
else if (mag >= 5.0) priority = '⚠️ Moderate — Stay alert';
else if (mag >= 4.0) priority = 'Light — No action needed';

// Build the Telegram message
const message = `${magEmoji} <b>Earthquake Detected Near Dhaka</b>

<b>Magnitude:</b> M${mag} — ${priority}
<b>Location:</b> ${place}
<b>Time:</b> ${time}
<b>Tsunami Risk:</b> ${tsunami}
<b>Felt Reports:</b> ${felt}
<b>USGS Alert Level:</b> ${alert}

<a href="${url}">View full details on USGS →</a>`;

// Return the formatted data for the Telegram node
return [{
  json: {
    quakeId,
    mag,
    place,
    time,
    tsunami,
    felt,
    alert,
    message
  }
}];
